element.default:
/**
 * EVALUATED ON SERVER
 * 
 * "current" is the Glide Record that is initialized based on configuration of 
 * Table, Param ID, Field ID
 * 
 * This function must return an object with two keys:
 * { 'result': true/false, errorMessage: '' }
 * Error message will be presented tot the user if errorMessage is filled out.
 * 
*/
(function(current) {
	if (current && current.isValidRecord() && !current.canRead()){
		return {
			result: false,
			errorMessage: 'Unfortunately you have no rights to view this record.'
		};		
	}
	return {
		result: true,
		errorMessage: ''
	};
})(current, navParams);

/**
 * EVALUATED ON CLIENT
 * 
 * "navParams" is an object of key-value pairs. All URL params starting with "scm_nav" are
 * parsed and put to this object. Example: the value of param "scm_nav_id" is accessible
 * as navParams.id
*/
(function(navParams) {
	return "Flyover title template";
})(navParams);

/**
 * EVALUATED ON CLIENT
 *
 * "navParams" is an object of key-value pairs. All URL params starting with "scm_nav" are
 * parsed and put to this object. Example: the value of param "scm_nav_id" is accessible
 * as navParams.id
 */
(function (navParams) {
	return {
		'table': '',
		'sys_id': navParams.sys_id,
		'view': 'sp',
		'trivialMessagePrefix': '',
		'autoCloseOnCompletedAction': true,
		'showDeletebutton': true,
		'deleteButtonInfo': {
			'title': 'Delete',
			'body': 'Do you really want to delete?',
		},
	};
})(navParams);

/**
 * EVALUATED ON CLIENT
 *
 * "renderResponse" is the object that is returned by "Render condition"
 * 
 * The script should return TRUE for flyover to be opened
 * The script should return FALSE if flyover should NOT be opened
 */
(function(navParams, renderResponse) {
	// Check the result of "Render condition script" and issue an error message if needed
	if (renderResponse.result != true){
		spUtil.addErrorMessage(renderResponse.errorMessage);
		return false;
	}
	return true;
})(navParams, renderResponse);
